"use client";

import { motion, AnimatePresence } from "framer-motion";
import { useState } from "react";
import { ArrowRight, ArrowLeft, Sparkles, CheckCircle2 } from "lucide-react";

const steps = [
  {
    id: 0,
    title: "Bienvenue sur Compressemos",
    subtitle:
      "On va configurer ton expérience en 3 petites étapes. Promis, ça va être rapide ✨",
  },
  {
    id: 1,
    title: "Quel est ton objectif ?",
    subtitle:
      "Ça nous aide à adapter les explications, les stats et l’interface.",
  },
  {
    id: 2,
    title: "C’est prêt 🎉",
    subtitle:
      "Tu peux maintenant commencer à compresser, comparer et explorer les algorithmes.",
  },
];

export default function OnboardingPage() {
  const [step, setStep] = useState(0);
  const [goal, setGoal] = useState<null | string>(null);

  const next = () => {
    if (step < steps.length - 1) setStep((s) => s + 1);
  };

  const prev = () => {
    if (step > 0) setStep((s) => s - 1);
  };

  const isLast = step === steps.length - 1;

  return (
    <div className="min-h-[80vh] flex items-center justify-center text-white">
      <div className="w-full max-w-3xl bg-white/10 backdrop-blur-2xl rounded-3xl border border-white/15 p-10 shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-3xl font-extrabold flex items-center gap-3">
              <Sparkles className="text-yellow-300" />
              Onboarding
            </h1>
            <p className="text-white/70 mt-1">
              Étape {step + 1} sur {steps.length}
            </p>
          </div>

          {/* Progress dots */}
          <div className="flex items-center gap-2">
            {steps.map((s) => (
              <div
                key={s.id}
                className={`h-2 rounded-full transition-all ${
                  s.id <= step ? "w-6 bg-white" : "w-2 bg-white/40"
                }`}
              />
            ))}
          </div>
        </div>

        {/* Step content */}
        <AnimatePresence mode="popLayout">
          <motion.div
            key={step}
            initial={{ opacity: 0, y: 25 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -25 }}
            transition={{ duration: 0.3 }}
          >
            <h2 className="text-2xl font-bold mb-3">{steps[step].title}</h2>
            <p className="text-white/70 mb-8">{steps[step].subtitle}</p>

            {step === 0 && (
              <div className="grid grid-cols-2 gap-6 mt-4">
                <div className="bg-black/20 rounded-2xl p-6 border border-white/10">
                  <h3 className="font-semibold mb-2">Démo / Projet scolaire</h3>
                  <p className="text-sm text-white/70">
                    Tu veux montrer le projet en soutenance, expliquer les
                    algorithmes de compression et impressionner le jury.
                  </p>
                </div>
                <div className="bg-black/20 rounded-2xl p-6 border border-white/10">
                  <h3 className="font-semibold mb-2">Exploration perso</h3>
                  <p className="text-sm text-white/70">
                    Tu explores la compression par curiosité, pour apprendre
                    comment les algos fonctionnent en pratique.
                  </p>
                </div>
              </div>
            )}

            {step === 1 && (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-4">
                {[
                  { id: "student", label: "Étudiant", desc: "Je prépare un projet / examen." },
                  {
                    id: "dev",
                    label: "Développeur",
                    desc: "Je veux intégrer ça dans une app.",
                  },
                  {
                    id: "curious",
                    label: "Curieux",
                    desc: "Je veux juste comprendre la compression.",
                  },
                ].map((g) => (
                  <button
                    key={g.id}
                    onClick={() => setGoal(g.id)}
                    className={`text-left bg-black/20 rounded-2xl p-4 border transition-all ${
                      goal === g.id
                        ? "border-white bg-white/10"
                        : "border-white/10 hover:border-white/40"
                    }`}
                  >
                    <p className="font-semibold mb-1">{g.label}</p>
                    <p className="text-xs text-white/70">{g.desc}</p>
                  </button>
                ))}
              </div>
            )}

            {step === 2 && (
              <div className="mt-6 space-y-4">
                <div className="flex items-center gap-3 bg-black/30 rounded-2xl p-4 border border-emerald-400/40">
                  <CheckCircle2 className="text-emerald-400" size={28} />
                  <div>
                    <p className="font-semibold">Tout est prêt 👌</p>
                    <p className="text-sm text-white/70">
                      Tu peux maintenant importer un fichier, choisir un
                      algorithme et visualiser les stats de compression.
                    </p>
                  </div>
                </div>
                <div className="text-sm text-white/60">
                  {goal === "student" && (
                    <p>
                      🎓 Mode étudiant activé : focus sur les explications, les
                      graphiques et la pédagogie.
                    </p>
                  )}
                  {goal === "dev" && (
                    <p>
                      💻 Mode développeur : pense à l’API, aux formats binaires,
                      et à l’intégration backend.
                    </p>
                  )}
                  {goal === "curious" && (
                    <p>
                      🧠 Mode découverte : explore les algorithmes sans pression
                      — amuse-toi !
                    </p>
                  )}
                  {!goal && (
                    <p>
                      Tu n’as pas choisi d’objectif, pas grave : tu peux
                      explorer librement l’application.
                    </p>
                  )}
                </div>
              </div>
            )}
          </motion.div>
        </AnimatePresence>

        {/* Navigation buttons */}
        <div className="mt-10 flex items-center justify-between">
          <button
            onClick={prev}
            disabled={step === 0}
            className="inline-flex items-center gap-2 text-sm text-white/70 disabled:opacity-40 disabled:cursor-not-allowed hover:text-white transition"
          >
            <ArrowLeft size={18} />
            Précédent
          </button>

          <button
            onClick={isLast ? () => (window.location.href = "/compress") : next}
            className="inline-flex items-center gap-2 bg-white text-black px-6 py-3 rounded-full text-sm font-semibold hover:scale-[1.03] active:scale-[0.98] transition"
          >
            {isLast ? (
              <>
                Commencer à compresser
                <ArrowRight size={18} />
              </>
            ) : (
              <>
                Suivant
                <ArrowRight size={18} />
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}
